+    pub fn try_resize_heap(&mut self, new_size: usize) -> Result<()> {
+        match &self.backing {
+            ShmRegionBacking::Heap(data) => {
+                let mut guard = data
+                    .lock()
+                    .unwrap_or_else(std::sync::PoisonError::into_inner);
+                if new_size > guard.len() {
