+                    guard
+                        .try_reserve_exact(new_size.saturating_sub(current_len))
+                        .map_err(|_| FrankenError::OutOfMemory)?;
+                    guard.resize(new_size, 0);
+                } else if new_size < guard.len() {
+                    guard.truncate(new_size);
